import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"四元素技艺","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/4.术法/魔法/四元素技艺.md","filePath":"4.资源分区/4.术法/魔法/四元素技艺.md"}'),s={name:"4.资源分区/4.术法/魔法/四元素技艺.md"};function o(d,b,_,l,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"四元素技艺",tabindex:"-1"},[t("四元素技艺 "),r("a",{class:"header-anchor",href:"#四元素技艺","aria-label":'Permalink to "四元素技艺"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调015")])])],-1),n('<h1 id="四元素技艺-1" tabindex="-1">四元素技艺 <a class="header-anchor" href="#四元素技艺-1" aria-label="Permalink to &quot;四元素技艺&quot;">​</a></h1><p>元素能量<br> D+1000<br> 描述：「多重元素是魔技」男人身上爆发出了多重元素能量交织的色彩。「感觉到了尽头、却又能发现进步的余地。然后说实话、也是我力量的根源，摇钱树，以及权利。」<br> 该技艺的本质是通过与构筑世界的基本四大元素混合，以掌握多重元素带来的力量，可以将自身已有的能量自由转换为不同的元素能量。</p><p>【元素聚合】<br> 先决：拥有任意通用能量池<br> 元素聚合的基础能力，将能量变成元素能量。所有后续技能必须在主动元素聚合的情况下使用，每个元素效果的使用都需要购买了对应元素技艺。<br> ·被动<br> 只要你的能量池不空，你就可以通过元素能量引发常态物理现象，这是个无支线级的环境效果。例如点燃物质，封冻液体，推动物件，产生气流，这些行动的影响范围的半径为15米，无须消耗能量，但也不能对人造成什么严重影响。</p><p>·主动<br> 以一个自由动作启动或切换，你的身上爆发出对应属性色彩的能量场并获得元素聚合的主动效果：<br> ·主动推动元素聚合时，可以选择将攻击所造成的伤害中的任意数量转换成对应元素属性的伤害类型，并获得【法破】特性。<br> 生效期间，你可以在地（腐蚀）、水（冻寒）、风（音波）、火（灼热）中选择一种作为当前的元素属性。<br> ·无论你选择哪种元素为当前属性，所有的元素技艺总是视为可以同时生效，但同一元素技艺必须按顺序购买升级。</p><p>每种元素技艺的解锁价格依次为D+500/C+1000/B+2000/A+4000，需要逐级购买。开启高级别某一元素的技艺会一并激活低级别该元素技艺的效果。</p><p>【地】<br> D级<br> 描述：借用构成世界的四大基本元素——地之元素，从身体中涌现出的，是大地的刚力。<br> 动作：花招动作<br> 能耗：2<br> 持续：一场景<br> 效果：你的力量检定和耐力检定分别增加4点增强加值。同时土之元素改变着你的身体，你免疫D级创伤来源的效果。</p><p>土之元素难以运用，如果一个不小心伤害到自己也是很有可能的。在C级之前，每次使用土之元素的技艺，你都会承受1点不可避免的严重伤害。</p><p>C级<br> 描述：与之前借用力量不同，如今混杂在体内的地之元素使身体也变成了大地般坚韧。<br> 动作：花招动作<br> 能耗：6<br> 持续：一场景<br> 效果：你的力量检定和耐力检定的增强加值提升到6点，并且由于地之元素寄托于身，防御力提高，你的天生防御提升4点。D级带来的创伤免疫提升到C级，以及获得了免疫C级毒素来源的效果的能力。</p><p>B级<br> 描述：将地之元素的力量的极致寄宿于身，几乎不受通常的攻击，即使是受到了伤害也被大幅度减小。<br> 动作：移动动作<br> 能耗：10<br> 持续：一场景<br> 效果：启动后你不会被普通物理行为影响或伤害到。但具有『法破』『能量』『力场』『幽冥』等特性的行为都可以正常伤害或影响到你。<br> 你的力量检定和耐力检定的增强加值提升到10点。<br> 你的毒素免疫能力等级不变，创伤免疫提升到B级。<br> 你的天生防御提升数值变为5点。<br> 你获得等同于你的耐力附加成功数的全伤害吸收，基于天生防御。</p><p>A级<br> 描述：你就是地之元素的化身，即使只是站在那里，也给人一种面对整个大地的感觉。<br> 动作：移动动作<br> 能耗：14<br> 持续：一场景<br> 效果：只要世界上仍有【物质】这个概念，就会有源源不断的力量提供给你。你的力量检定和耐力检定的增强加值提升到力量属性点。<br> 你对于毒素、创伤来源的负面效果免疫提升至A级<br> 天生防御提升效果，改为获得等同于你的耐力值的数值，以及等于B级别获得的全吸收点数的封闭（同样基于天生防御），以及获得【防能量武器】与【超级坚韧】（关于封闭特性的判定上，视你的天生防御为盔甲防御，防弹防能量和全吸收效果都是基于你的天生防御的）。</p><p>你不会被普通物理行为影响或伤害到。但具有『法破』『能量』『力场』『幽冥』等特性的行为都可以正常伤害或影响到你。</p><p>【水】<br> D级<br> 描述：借用构成世界的四大基本元素——水之元素，你能感受到事物的流转。<br> 动作：花招动作<br> 能耗：2<br> 持续：一场景<br> 效果：感受事物的流转，你很快就能察觉出针对你的不和谐气息——这视为一种新建的非线性感知能力，能够察觉到感知范围内的杀意位置来源，即使是自动机枪，也会被你的心灵感应捕捉到，只能模糊定位，这不会给你带来侦测能力，但可能有剧情上的效果。</p><p>此外，你能够用水构成墙壁防御敌人的攻击，这会提供给你微弱的减伤效果，这会给你带来4点偏斜防御。</p><p>C级<br> 描述：将心进一步寄托于水元素的流转，空气的，声音的，力量的，森罗万象的流转，宛如与外界融为一体。<br> 动作：花招动作<br> 能耗：6<br> 持续：一场景<br> 效果：将心寄托于水的流动中，你免疫C级影响心灵与同等级免疫措手不及效果。你在D级获得的感知方式提升为强感知方式。</p><p>面对敌人的攻击，你就像看见了水流中的一颗落叶，像水的流动一样，自然而然地避开了，上一级的偏斜防御提升至6点。</p><p>宛如流水一般，将武器挥出，你能轻易地斩开巨龙的鳞甲，这不是依靠蛮力斩开的，而是水之元素的力量，你的攻击提升5点破甲。</p><p>B级<br> 描述：顺应世界的流转，仿佛处于安静的水流当中，自然而然的做出行动。<br> 动作：花招动作<br> 能耗：10<br> 持续：一场景<br> 效果：清流透明的心，使你免疫B级措手不及与影响心灵的效果。</p><p>你的心再无迷惘，你能用武器偏开火球，破掉结界。你在上个等级获得的攻击破甲提升改为10点，同时获得等量的破魔。</p><p>此外，你在上个等级获得的偏斜防御提升至15点。</p><p>A级：<br> 描述：不向外求，而是向内。意如烈火，心如明镜，万事万物的流转，已经彻底掌握，你就是水之元素的化身。<br> 动作：移动动作<br> 能耗：14<br> 持续：一场景<br> 效果：森罗万象的流动变化，你都了解于心，让你能提前判断，做出响应。这个状态下，你获得先前等级的所有效果，且你在上个等级获得的心灵影响免疫与措手免疫提升至A级。</p><p>只要世界上仍有【时间】这个概念，你就可以感应森罗万象的流动，然后顺着流动斩过去，这一击甚至能将巨龙吐过来的龙息劈开。<br> 每轮一次，你免疫一次附带能量的远程攻击带来的所有伤害与负面效果，这是一个A级别、时空来源的无敌效果，视为你将所有加身的外在能量直接击灭。</p><p>【风】<br> D级<br> 描述：借用构成世界的四大基本元素——风之元素，将自身不可思议的与风混为一体。<br> 动作：花招动作<br> 能耗：2<br> 持续：一场景<br> 效果：用耳听着风声，就能像亲眼所见似的感知到周围的一切情况，这是D级魔幻本质的侦测能力，基于听觉，现在你的听觉感知方式提升至强感知方式，可以精确定位。<br> 由于风之元素的力量，你在敏捷检定上获得1DP增强加值，以及获得1DP的闪避防御。</p><p>C级<br> 描述：与以往不同，无需掀起风儿，你的身体里，充满了风的力量。<br> 动作：花招动作<br> 能耗：6<br> 持续：一场景<br> 效果：<br> 由于风之元素的支配力提升，你在D级获得的魔幻本质侦测能力提高到C级，敏捷检定与闪避防御数值提升至3DP。</p><p>由于风之元素对于行动的增益，你的移动速度增加20米，近战攻击提升5点高速，能够宛如子弹一样快速的挥动武器。</p><p>B级<br> 描述：风是你的双眼，是你的身躯，自由自在，想到哪里就去哪里。<br> 动作：移动动作<br> 能耗：10<br> 持续：一场景<br> 效果：<br> 现在风成为了你的眼睛，它流动的地方你都会如同亲眼看到，听到，接触到一般。你在C级获得的侦测能力提高到B级，敏捷检定与闪避防御数值提升至8DP。</p><p>借助风元素的力量，你每回合可以自由动作进行一次移动，并如同风一样获得等同于你的基础速度的飞行能力，机动性完美。</p><p>A级：<br> 描述：你就是风之元素的化身，若闭上双眼去感知你，就会发现与暴风无异。<br> 动作：移动动作<br> 能耗：14<br> 持续：一场景<br> 效果：只要世界上仍然存在【空间】这个概念，你就能用风之感知来替代你的五感，你在B级获得的侦测能力提高到A级。敏捷检定与闪避防御数值提升至12DP。</p><p>现在你就是大自然的风之化身，如果别人闭上眼睛，用其他能力来感知你，他只会感觉到无边的暴风覆盖了一切，科技类的摄像头，魔幻类的留影仪，或是特异本质的记录效果中，你的身影永远只会显露出待在原地的风暴的影象。这是因为强大的风之元素的气息干涉世界，所以，除非你刻意收敛，否则只能是这样，这是一个B级魔幻本质的反侦测效果。</p><p>风之元素时时萦绕在你的周围，你现在的移动可视为A级别、时空来源的传送效果。</p><p>将风之元素完美寄宿于行动中去，你将不受外在环境的影响，你免疫A级环境来源的负面效果。</p><p>【火】<br> D级<br> 描述：借用构成世界的四大基本元素——火之元素，催生出灼热的业火。<br> 动作：花招动作<br> 能耗：2<br> 持续：一场景<br> 效果：将此火炎寄在武器上，便可提高些许威力吧。你的攻击检定与决心检定获得3DP能量加值。</p><p>C级<br> 描述：将斗争心燃烧到极致，红莲的业火威力大增，足以撕裂所有敌人。<br> 动作：花招动作<br> 能耗：6<br> 持续：一场景<br> 效果：现在，你的攻击检定与决心检定在上一个等级获得的能量加值提升至6点，武器伤害提升3L。<br> 启动后，每轮你所使用第一次绑定的通用能量消耗会减少3点（最低为1）。</p><p>B级<br> 描述：火之元素的极致，将灼热的业火寄宿于技，内心却保持着平静，使用平常心都将其支配。<br> 动作：花招动作<br> 能耗：10<br> 持续：一场景<br> 效果：你被灼热的业火包围，在这个状态下你的攻击检定与决心检定获得的能量加值提升至10点。<br> 当你进行攻击时，命中后会额外附带2点不可豁免的燃烧异常不良点数。</p><p>A级：<br> 描述：点燃罪孽，劫尽琉璃生，此为火之牺牲。你就是火之元素的化身，燃烧一切的征兆。<br> 动作：移动动作<br> 能耗：14<br> 持续：一场景<br> 效果：火之元素，是世界【能量】的象征。<br> 强烈的斗争心与火之元素产生共鸣，你的战斗技巧获得了极大的飞跃：<br> 你现在能以自由动作进行一次格挡，你在之前等级获得的攻击与决心检定不变，但是在攻击敌人，可以轻易地绕开敌人的盔甲和天生防御，如同具有【接触攻击】一样。</p><p>业火不仅仅只能对敌人使用，你也可以用业火灼热自身，你免疫A级的诅咒来源与命运来源的能力。</p><p>当你开启A级火元素技艺后，你可以标准动作点燃自己，让斗争心突破极限，使绑定的能量处于满值状态，此时你从火元素技艺A级以外获得的数据*3倍处理（提升至的数值依旧只计算提升后），但是当你燃尽生命的时候你会无可避免地走向死亡。<br> 这个效果可以给予其他人使用，只要其他友方单位处于你的决心*20米范围内，就可以使用自由动作点燃自己，立刻获得如你一样点燃自己带来的好处，以及火元素技艺A级之前的数值*3倍的好处，并在场景结束后立刻死亡。<br> 如果使用该效果后，使用者会因为复活的凭依也被一并燃尽，无法以任何方法进行复活。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',38)])])}const A=p(s,[["render",o]]);export{D as __pageData,A as default};
